// Enterprise schema: 21 collections with embedded arrays.
// This creates the full 40-entity domain as MongoDB collections (no strict validators).
export async function ensureSchema(db) {
  const { generateMongoSchema } = await import("../scripts/enterprise-schema-gen.mjs");
  const gen = generateMongoSchema();
  const existing = await db.listCollections().toArray();
  const existingNames = new Set(existing.map((c) => c.name));
  for (const name of gen.collectionNames) {
    if (!existingNames.has(name)) {
      await db.createCollection(name);
    } else {
      // Remove any strict validator from existing collections
      await db.command({ collMod: name, validator: {}, validationLevel: "off" });
    }
  }
}
